def extract_matn_segment(text):
    # find the earliest occurrence of "خيركم خيركم لأهله"
    idx = text.find("خيركم خيركم لأهله")
    if idx == -1:
        idx = text.find("خيركم خيركم")
    if idx == -1:
        return None
    # find end - try to end at first " ." or " ."
    end = len(text)
    # prefer to end at " ."
    # but DB uses Arabic comma ، and then maybe period .
    # We'll attempt to end at the first period after idx.
    dot = text.find(".", idx)
    if dot != -1:
        end = dot+1
    else:
        # else end at end of sentence before bracket or after hadith closes punctuation
        # maybe " ."
        pass
    return text[idx:end].strip()

